import React, { useMemo } from 'react';
import { useIntl } from 'gatsby-plugin-intl';
import PropTypes from 'prop-types';
import { Typography } from '@material-ui/core';
import { makeStyles } from '@material-ui/core/styles';

// Components
import Layout from '../components/Layout';
import SEO from '../components/SEO';

// Utils
import PostsList from '../components/PostsList';
import { capitalizeString } from '../utils/gatsby-frontend-helpers';

const useStyles = makeStyles((theme) => ({
    simplePostsListWrapper: {
        marginBottom: '10px',
    },
    categoryText: {
        margin: '10px 0',
    },
}));

const CategoryPageTemplate = ({ location, pageContext }) => {
    const { posts, title, robots, categoryImage } = pageContext;
    const intl = useIntl();
    const classes = useStyles();
    const pageTitle = useMemo(
        () => {
            const categoryName = intl.formatMessage({ id: `blog_categories.${title}` });
            return `${intl.formatMessage({ id: 'posts_on_category' })}${capitalizeString(categoryName)}`;
        },
        [intl, title]
    );

    return (
        <Layout>
            <SEO
                lang={intl.locale}
                pathname={location?.pathname}
                title={pageTitle}
                robots={robots}
                ogImage={categoryImage?.childImageSharp?.original?.src}
                keywords={[
                    intl.formatMessage({ id: 'categories' }),
                    intl.formatMessage({ id: 'blog_categories.games' }),
                    intl.formatMessage({ id: 'blog_categories.general' }),
                    intl.formatMessage({ id: 'blog_categories.tips' }),
                    intl.formatMessage({ id: 'blog_categories.events' }),
                    intl.formatMessage({ id: 'blog_categories.coding' }),
                    intl.formatMessage({ id: 'blog_categories.funny' }),
                ]}
            />
            <Typography
                className={classes.categoryText}
                color="textPrimary"
                variant="h4"
            >
                {pageTitle}
            </Typography>
            <PostsList
                className={classes.simplePostsListWrapper}
                posts={posts}
                locale={intl.locale}
            />
        </Layout>
    );
};

CategoryPageTemplate.propTypes = {
    pageContext: PropTypes.object.isRequired,
    location: PropTypes.object.isRequired,
};

export default CategoryPageTemplate;
